+      }
+
+      
+    }
+
+    for(JointIndex i=2;i<(JointIndex)model.njoints-1; ++i)
+    {
+
+      if (data.accumulation_descendant[i] == i)
+      {
+        size_t an_i = data.accumulation_ancestor[i];
+        data.spatial_inv_inertia[i].noalias() += data.extended_motion_propagator[i]*
